def transition(state, action):
    s = dict(state)
    name = action.get("name")
    HIGH = 50
    if name == "score":
        risk = (s["amount"] // 100) + s["merchant_risk"] + s["velocity"] * 5
        s["score"] = max(0, min(100, int(risk)))
        s["scored"] = True
        s["flagged"] = s["score"] >= HIGH
    elif name == "hold":
        # A hold can be placed on a live transaction (never on a frozen card).
        if s["status"] in ("pending", "released") and not s["card_frozen"]:
            s["status"] = "held"
            s["holds_placed"] = s["holds_placed"] + 1
    elif name == "release":
        # Releasing clears an existing hold and lets the transaction settle.
        if s["status"] == "held":
            s["status"] = "released"
            s["releases"] = s["releases"] + 1
    elif name == "block":
        # Blocking is terminal: it freezes the card and stops the transaction.
        if s["status"] != "blocked":
            s["status"] = "blocked"
            s["card_frozen"] = True
            s["blocks"] = s["blocks"] + 1
    return s

