def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower(); v = v.strip()
        if k in ('amount', 'merchant_risk', 'velocity'):
            n = int(v) if v.lstrip('-').isdigit() else 0
            out[k] = max(0, n)
    return out
